class CelticWindError(Exception):
    """Base exception for all CelticWind pipeline errors."""
    pass

class ValidationError(CelticWindError):
    """Raised when a data record fails validation."""
    def __init__(self, meter_id: str, field: str, reason: str):
        self.meter_id = meter_id
        self.field = field
        self.reason = reason
        super().__init__(f'{meter_id}: {field} — {reason}')

class SchemaError(CelticWindError):
    """Raised when input data does not match the expected schema."""
    def __init__(self, missing_columns: set[str], extra_columns: set[str]):
        self.missing_columns = missing_columns
        self.extra_columns = extra_columns
        super().__init__(
            f'Schema mismatch: missing={missing_columns}, extra={extra_columns}'
        )

class SourceUnavailableError(CelticWindError):
    """Raised when an external data source cannot be reached."""
    def __init__(self, source_name: str, reason: str):
        self.source_name = source_name
        super().__init__(f'{source_name} unavailable: {reason}')

def validate_reading(raw: dict) -> dict:
    """Validate a single meter reading. Raises ValidationError on failure."""
    meter_id = raw.get('meter_id')
    if not meter_id:
        raise ValidationError('UNKNOWN', 'meter_id', 'missing or empty')

    try:
        daily_kw = float(raw['daily_kw'])
    except (ValueError, KeyError):
        raise ValidationError(meter_id, 'daily_kw', f"invalid value: {raw.get('daily_kw')}")

    if daily_kw < 0 or daily_kw > 5000:
        raise ValidationError(meter_id, 'daily_kw', f'out of range: {daily_kw}')

    return {'meter_id': meter_id, 'daily_kw': daily_kw, 'region': raw.get('region', '').upper()}

