@dataclass(frozen=True)
class ValidationRules:
    """Domain-specific validation constraints for meter readings."""
    min_daily_kw: float = 0.0
    max_daily_kw: float = 5000.0
    valid_regions: frozenset[str] = frozenset({'DUBLIN', 'CORK', 'GALWAY', 'BELFAST'})
    max_date: date | None = None  # if set, reject dates after this

    def validate_daily_kw(self, value: float) -> None:
        if value < self.min_daily_kw:
            raise ValueError(f'daily_kw {value} below minimum {self.min_daily_kw}')
        if value > self.max_daily_kw:
            raise ValueError(f'daily_kw {value} above maximum {self.max_daily_kw}')

    def validate_region(self, value: str) -> None:
        if value not in self.valid_regions:
            raise ValueError(f'unknown region: {value}')

    def validate_date(self, value: date) -> None:
        if self.max_date and value > self.max_date:
            raise ValueError(f'date {value} is in the future (max: {self.max_date})')

