from celticwind.api import EpexPriceClient

def enrich_with_prices(readings: list[dict], config: dict) -> list[dict]:
    """Add energy prices to Silver meter readings."""
    client = EpexPriceClient(cache_dir=Path(config['paths']['cache_dir']))

    # Get unique dates from the readings
    dates = sorted(set(r['date'] for r in readings))

    # Fetch prices for each date (cached after first fetch)
    prices_by_date = {}
    for date in dates:
        prices_by_date[date] = {p['hour']: p for p in client.get_prices(date)}

    # Enrich each reading with its hourly price
    enriched = []
    for reading in readings:
        hour_prices = prices_by_date.get(reading['date'], {})
        reading_hour = int(reading.get('hour', 0))
        price = hour_prices.get(reading_hour, {})
        enriched.append({
            **reading,
            'price_eur_mwh': price.get('price_eur_mwh'),
        })
    return enriched

