def match_reading_to_price(
    reading: dict,
    prices: list[dict],
) -> dict | None:
    """Find the energy price that matches a meter reading's UTC timestamp.

    Both the reading and the prices must have UTC timestamps
    (normalized during Bronze-to-Silver transformation).
    """
    reading_ts = datetime.fromisoformat(reading['timestamp_utc'])
    reading_hour = reading_ts.replace(minute=0, second=0, microsecond=0)

    for price in prices:
        price_ts = datetime.fromisoformat(price['timestamp_utc'])
        if price_ts == reading_hour:
            return {
                **reading,
                'price_eur_mwh': price['price_eur_mwh'],
                'price_timestamp_utc': price['timestamp_utc'],
            }
    return None  # no matching price found

