import time
import logging

logger = logging.getLogger(__name__)

def retry_with_backoff(
    func,
    *args,
    max_retries: int = 3,
    initial_delay: float = 1.0,
    backoff_factor: float = 2.0,
    retryable_exceptions: tuple = (ConnectionError, TimeoutError),
    **kwargs,
):
    """Retry a function with exponential backoff on transient errors."""
    delay = initial_delay
    for attempt in range(1, max_retries + 1):
        try:
            return func(*args, **kwargs)
        except retryable_exceptions as e:
            if attempt == max_retries:
                logger.error(
                    'Failed after %d attempts: %s', max_retries, e
                )
                raise  # re-raise on final attempt
            logger.warning(
                'Attempt %d/%d failed: %s. Retrying in %.1fs',
                attempt, max_retries, e, delay,
            )
            time.sleep(delay)
            delay *= backoff_factor  # 1s, 2s, 4s, 8s, ...

def validate_schema(
    readings: list[dict],
    required_columns: set[str],
) -> None:
    """Validate that all required columns are present in the data.

    Raises SchemaError if columns are missing or unexpected.
    """
    if not readings:
        return  # empty data passes schema validation

    actual_columns = set(readings[0].keys())
    missing = required_columns - actual_columns
    extra = actual_columns - required_columns

    if missing:
        raise SchemaError(missing_columns=missing, extra_columns=extra)

    if extra:
        logger.warning(
            'Unexpected columns found (will be ignored): %s', extra
        )

