import requests
import logging

logger = logging.getLogger(__name__)

def fetch_with_error_handling(url: str, params: dict, headers: dict) -> dict | None:
    """Fetch JSON from an API with categorized error handling."""
    try:
        response = requests.get(url, params=params, headers=headers, timeout=30)
        response.raise_for_status()
        return response.json()

    except requests.Timeout:
        logger.error('API timeout after 30s: %s', url)
        raise  # let retry logic handle this

    except requests.HTTPError as e:
        status = e.response.status_code
        if status == 401:
            logger.error('Authentication failed for %s — check API key', url)
            raise  # do not retry — key is wrong
        elif status == 404:
            logger.warning('Data not found at %s with params %s', url, params)
            return None  # no data — not an error, just missing
        elif status == 429:
            retry_after = int(e.response.headers.get('Retry-After', 60))
            logger.warning('Rate limited by %s — retry after %ds', url, retry_after)
            raise  # let retry logic handle with the Retry-After delay
        else:
            logger.error('API error %d from %s: %s', status, url, e)
            raise  # let retry logic handle 5xx errors

    except requests.ConnectionError:
        logger.error('Connection failed to %s', url)
        raise  # let retry logic handle network issues

def fetch_with_retry_after(
    url: str,
    headers: dict,
    params: dict,
    max_retries: int = 3,
) -> dict:
    """Fetch a URL, respecting the Retry-After header on 429 responses."""
    for attempt in range(1, max_retries + 1):
        response = requests.get(url, params=params, headers=headers, timeout=30)

        if response.status_code == 429:
            retry_after = int(response.headers.get('Retry-After', 60))
            logger.warning(
                'Rate limited (attempt %d/%d). Waiting %ds',
                attempt, max_retries, retry_after,
            )
            time.sleep(retry_after)
            continue

        response.raise_for_status()
        return response.json()

    raise requests.HTTPError(f'Rate limited after {max_retries} attempts')

