    except requests.ConnectTimeout:
        logger.error('Connect timeout (>5s) for %s — server may be unreachable', url)
        raise  # retryable

    except requests.ReadTimeout:
        logger.error('Read timeout (>30s) for %s — server may be overloaded', url)
        raise  # retryable

    except requests.ConnectionError as e:
        logger.error('Connection failed to %s: %s', url, e)
        raise  # retryable (network may recover)

    except requests.JSONDecodeError:
        logger.error('Invalid JSON response from %s', url)
        return None  # not retryable — the response is malformed

